```bash
awk 'BEGIN{start=67;end=115}
NR==start{
print "  /// A range of powers-of-2 vectorization factors with fixed start and";
print "  /// adjustable end. The range includes start and excludes end, e.g.,:";
print "  /// [1, 16) = {1, 2, 4, 8}";
print "  struct VFRange {";
print "    // A power of 2.";
print "    const ElementCount Start;";
print "";
print "    // A power of 2. If End <= Start range is empty.";
print "    ElementCount End;";
print "";
print "    bool isEmpty() const {";
print "      return End.getKnownMinValue() <= Start.getKnownMinValue();";
print "    }";
print "";
print "    VFRange(const ElementCount &Start, const ElementCount &End)";
print "        : Start(Start), End(End) {";
print "      assert(Start.isScalable() == End.isScalable() &&";
print "             \"Both Start and End should have the same scalable flag\");";
print "      assert(isPowerOf2_32(Start.getKnownMinValue()) &&";
print "             \"Expected Start to be a power of 2\");";
print "      assert(isPowerOf2_32(End.getKnownMinValue()) &&";
print "             \"Expected End to be a power of 2\");";
print "    }";
print "";
print "    /// Iterator to iterate over vectorization factors in a VFRange.";
print "    class iterator";
print "        : public iterator_facade_base<iterator, std::forward_iterator_tag,";
print "                                      ElementCount> {";
print "      ElementCount VF;";
print "";
print "    public:";
print "      iterator(ElementCount VF) : VF(VF) {}";
print "";
print "      bool operator==(const iterator &Other) const { return VF == Other.VF; }";
print "";
print "      ElementCount operator*() const { return VF; }";
print "";
print "      iterator &operator++() {";
print "        VF *= 2;";
print "        return *this;";
print "      }";
print "    };";
print "";
print "    iterator begin() { return iterator(Start); }";
print "    iterator end() {";
print "      assert(isPowerOf2_32(End.getKnownMinValue()));";
print "      return iterator(End);";
print "    }";
print "  };";
skip=1; next
}
skip && NR<end{next}
{print}
' llvm/lib/Transforms/Vectorize/VPlanHelpers.h > /tmp/VPlanHelpers.h.fix && mv /tmp/VPlanHelpers.h.fix llvm/lib/Transforms/Vectorize/VPlanHelpers.h && nl -ba llvm/lib/Transforms/Vectorize/VPlanHelpers.h | sed -n '64,118p' && nl -ba llvm/lib/Transforms/Vectorize/LoopVectorize.cpp | sed -n '9226,9234p'
